namespace sv_46d05dd08932461fbc2a7d640ec70872.Services;

/// <summary>
/// In-memory demo implementation of IChatService for development and testing.
/// </summary>
public class DemoChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly List<Message> _messages;
    private int _nextMessageId;

    public DemoChatService()
    {
        _channels = new()
        {
            new(1, "general", "General discussion for the team", 3),
            new(2, "engineering", "Engineering updates and questions", 0),
            new(3, "design", "Design reviews and feedback", 1),
            new(4, "random", "Off-topic chat and fun stuff", 5),
            new(5, "announcements", "Important team announcements", 0),
        };

        var now = DateTime.UtcNow;
        _messages = new()
        {
            new(1, 1, "Alice", "Hey team, welcome to the new chat app! 🎉", now.AddHours(-5), null, new() { new("🎉", new() { "Bob", "Carol" }), new("👍", new() { "Dave" }) }),
            new(2, 1, "Bob", "Looks great! Love the new design.", now.AddHours(-4.5), null, new() { new("❤️", new() { "Alice" }) }),
            new(3, 1, "Carol", "Quick question — are we migrating the old messages?", now.AddHours(-4), null, new()),
            new(4, 1, "Alice", "Yes, we'll migrate them over the weekend.", now.AddHours(-3.8), 3, new() { new("👍", new() { "Carol" }) }),
            new(5, 1, "Dave", "I can help with the migration script.", now.AddHours(-3.5), 3, new()),
            new(6, 1, "Bob", "Has anyone reviewed the API docs yet?", now.AddHours(-2), null, new()),
            new(7, 1, "Carol", "I'll take a look this afternoon.", now.AddMinutes(-45), null, new()),
            new(8, 1, "Dave", "Don't forget the standup at 3 PM!", now.AddMinutes(-10), null, new() { new("👀", new() { "Alice", "Bob" }) }),
            new(9, 2, "Dave", "Deployed v2.3.1 to staging.", now.AddHours(-1), null, new() { new("🚀", new() { "Alice" }) }),
            new(10, 2, "Alice", "Running integration tests now.", now.AddMinutes(-30), null, new()),
            new(11, 3, "Carol", "New mockups are ready for review.", now.AddHours(-2), null, new() { new("👀", new() { "Bob" }) }),
        };

        _nextMessageId = 12;
    }

    public Task<List<Channel>> GetChannelsAsync()
    {
        return Task.FromResult(_channels.ToList());
    }

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var messages = _messages
            .Where(m => m.ChannelId == channelId && m.ReplyToId == null)
            .OrderByDescending(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .OrderBy(m => m.SentAt)
            .ToList();
        return Task.FromResult(messages);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var id = Interlocked.Increment(ref _nextMessageId);
        var message = new Message(id, channelId, "You", content, DateTime.UtcNow, replyToId, new());
        _messages.Add(message);
        return Task.FromResult(message);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var root = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        var replies = _messages.Where(m => m.ReplyToId == rootMessageId).OrderBy(m => m.SentAt).ToList();
        var result = new List<Message>();
        if (root != null) result.Add(root);
        result.AddRange(replies);
        return Task.FromResult(result);
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var idx = _messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return Task.CompletedTask;

        var msg = _messages[idx];
        var reactions = msg.Reactions.ToList();
        var existing = reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing != null)
        {
            reactions.Remove(existing);
            var users = existing.Users.ToList();
            if (!users.Contains("You")) users.Add("You");
            reactions.Add(new Reaction(emoji, users));
        }
        else
        {
            reactions.Add(new Reaction(emoji, new() { "You" }));
        }
        _messages[idx] = msg with { Reactions = reactions };
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
        return Task.CompletedTask;
    }
}

