{"file_text": "@* Reusable message input: textarea + send/reply button *@

<div class="message-input-area">
    <textarea class="message-textarea"
              placeholder="@Placeholder"
              @bind="Text"
              @onkeydown="HandleKeyDown"
              rows="1"></textarea>
    <button class="send-btn" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(Text)">
