toolArgs.file_text:
@* A single message with author, timestamp, content, reactions, and hover actions *@

<div class="message-bubble @(IsThreadRoot ? "thread-root" : "")"
     @onmouseenter="() => _showActions = true"
     @onmouseleave="HandleMouseLeave">
    <div class="msg-header">
        <span class="msg-author">@Message.Author</span>
        <span class="msg-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="msg-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="msg-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ReplyCount > 0 && !HideThreadLink)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="msg-actions">
            @if (!HideThreadLink)
            {
                <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                    💬
                </button>
            }
            <div class="react-wrapper">
                <button class="action-btn" @onclick="TogglePicker" @onclick:stopPropagation="true" title="Add reaction">
                    😀
                </button>
                @if (_showPicker)
                {
                    <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
                }
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public bool HideThreadLink { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _showActions;
    private bool _showPicker;

    private void HandleMouseLeave()
    {
        _showActions = false;
        _showPicker = false;
    }

    private void TogglePicker() => _showPicker = !_showPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        _showPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

