toolArgs.file_text:
.message-bubble {
    padding: 6px 16px;
    position: relative;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-bubble:hover {
    background-color: rgba(255, 255, 255, 0.03);
}

.msg-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.msg-author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #e0e0e0;
}

.msg-time {
    font-size: 0.75rem;
    color: #72767d;
}

.msg-content {
    font-size: 0.9rem;
    color: #ccc;
    line-height: 1.45;
    word-break: break-word;
}

.msg-reactions {
    display: flex;
    gap: 4px;
    flex-wrap: wrap;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: rgba(88, 101, 242, 0.15);
    border: 1px solid rgba(88, 101, 242, 0.3);
    border-radius: 6px;
    padding: 2px 8px;
    font-size: 0.8rem;
    color: #c4c9ce;
    cursor: default;
}

.thread-link {
    background: none;
    border: none;
    color: #5865f2;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
}

.thread-link:hover {
    text-decoration: underline;
}

.msg-actions {
    position: absolute;
    top: -8px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #2b2d31;
    border: 1px solid #3a3c41;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
}

.action-btn {
    background: none;
    border: none;
    font-size: 1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
    transition: background-color 0.15s;
}

.action-btn:hover {
    background-color: rgba(255, 255, 255, 0.1);
}

.react-wrapper {
    position: relative;
}

